import fetch from"node-fetch";import{writeIcon}from"./write-icon.js";import{STUB_PATH_PHP}from"../utils/stub-path.js";const SINGLE_URL="https://ppicons.tsnc.tech/icons";export async function generateIcon(t,o,n=!1){const c=`${SINGLE_URL}?icon=${encodeURIComponent(t)}`,e=await fetch(c);if(!e.ok)throw new Error(`Could not fetch "${t}": ${e.statusText} – ${c}`);const r=await e.json();return writeIcon(r,o,STUB_PATH_PHP,n)}